cd /tmp/sv-025e374d4e89415fa9b2a6294a42c495/moderate-msbuild-properties && dotnet package list --format json 2>/dev/null | python3 -m json.tool > after-cpm-packages.json && python3 -c "
import json
with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)
# Compare per project
for bp, ap in zip(baseline['projects'], after['projects']):
    proj = bp['path'].split('/')[-1]
    for bf, af in zip(bp['frameworks'], ap['frameworks']):
        b_pkgs = {p['id']: p['resolvedVersion'] for p in bf.get('topLevelPackages', [])}
        a_pkgs = {p['id']: p['resolvedVersion'] for p in af.get('topLevelPackages', [])}
        for pkg in sorted(set(list(b_pkgs.keys()) + list(a_pkgs.keys()))):
            bv = b_pkgs.get(pkg, 'N/A')
            av = a_pkgs.get(pkg, 'N/A')
            status = 'CHANGED' if bv != av else 'OK'
            print(f'{proj:20s} {pkg:55s} {bv:10s} -> {av:10s} [{status}]')
"

